// Re-assert both ensures-conjuncts so z3 instantiates the `forall|i|` from
// each run with the same triggers; otherwise the two quantifiers stay disjoint.
assert(r1.0 == forall|i: int| #![auto] lo <= i <= hi ==> self_.vals@[i]@ == v@);
assert(r2.0 == forall|i: int| #![auto] lo <= i <= hi ==> self_.vals@[i]@ == v@);

// Both `.0`s equal the same predicate, hence equal to each other.
assert(r1.0 == r2.0);

// When the all-equal predicate fails, the second component is fully pinned by
// the ensures, so r1.1 and r2.1 must agree as well.
if !r1.0 {
    assert(!r2.0);
    assert(r1.1 == (self_.vals@[hi as int]@ != v@
        && forall|i: int| #![auto] lo <= i < hi ==> self_.vals@[i]@ == v@));
    assert(r2.1 == (self_.vals@[hi as int]@ != v@
        && forall|i: int| #![auto] lo <= i < hi ==> self_.vals@[i]@ == v@));
    assert(r1.1 == r2.1);
}
